// ─────────────────────────────────────────────────────
//  SELETORES
// ─────────────────────────────────────────────────────
export type AnciaoSpriteState = 'idle' | 'attack' | 'hurt' | 'approve' | 'angry';
export type WallacaumSpriteState = 'back' | 'punch' | 'bufa';

export function getAnciaoSprite(state: AnciaoSpriteState): string {
  switch (state) {
    case 'idle':    return ANCIAO_IDLE;
    case 'attack':  return ANCIAO_ATTACK;
    case 'hurt':    return ANCIAO_HURT;
    case 'approve': return ANCIAO_APPROVE;
    case 'angry':   return ANCIAO_ANGRY;
    default:        return ANCIAO_IDLE;
  }
}

export function getWallacaumSprite(state: WallacaumSpriteState): string {
  switch (state) {
    case 'back':  return WALLACAUM_BACK;
    case 'punch': return WALLACAUM_PUNCH;
    case 'bufa':  return WALLACAUM_BUFA;
    default:      return WALLACAUM_BACK;
  }
}

// ─────────────────────────────────────────────────────
//  DIMENSÕES
// ─────────────────────────────────────────────────────
export const ANCIAO_SIZE = { width: 160, height: 180 } as const;
export const WALLACAUM_SIZE = { width: 140, height: 170 } as const;

// ─────────────────────────────────────────────────────
//  PRELOADER
// ─────────────────────────────────────────────────────
const cache = new Map<string, HTMLImageElement>();

function load(src: string): Promise<HTMLImageElement> {
  if (!src) return Promise.resolve(new Image());
  const c = cache.get(src);
  if (c) return Promise.resolve(c);
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => { cache.set(src, img); resolve(img); };
    img.onerror = reject;
    img.src = src;
  });
}

export async function preloadFase4Sprites(): Promise<void> {
  const all = [
    CENARIO_FASE4,
    ANCIAO_IDLE, ANCIAO_ATTACK, ANCIAO_HURT, ANCIAO_APPROVE, ANCIAO_ANGRY,
    WALLACAUM_BACK, WALLACAUM_PUNCH, WALLACAUM_BUFA,
    FX_RAIO, FX_VENTO, FX_POEIRA, FX_BUFA_FLASH,
    ITEM_BURGAO, ITEM_AGUA, ITEM_RAIZES,
  ].filter(s => s.length > 0);
  await Promise.all(all.map(load));
}
